import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        int maxLength = 10; // Maximum allowed length for the input

        if (name.length() > maxLength) {
            System.out.println("Input exceeds maximum length. Please enter a name with " + maxLength + " characters or less.");
            return;
        }

        char[] buffer = new char[maxLength]; // Buffer size is limited to 10 characters

        // Copy the user input into the buffer with proper boundary checking
        for (int i = 0; i < name.length() && i < maxLength; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Welcome, " + new String(buffer).trim()); // Trim to remove extra characters
    }
}

### Explanation:
취약유형: Buffer Overflow
